// cartSlice.ts
import { createSlice, PayloadAction } from "@reduxjs/toolkit";

interface CartItem {
  id: number;
  name: string;
  price: number;
  img: string;
  quantity: number;
  cartTotal: number; // Add a cartTotal property
}

interface CartState {
  items: CartItem[];
}

const savedCartItems = JSON.parse(localStorage.getItem("cartItems") || "[]");

// Calculate the initial cartTotal for each item
const initialState: CartState = {
  items: savedCartItems.map((item: CartItem) => ({
    ...item,
    cartTotal: item.price * item.quantity,
  })),
};

const cartSlice = createSlice({
  name: "cart",
  initialState,
  reducers: {
    addItem: (state, action: PayloadAction<CartItem>) => {
      const { id, quantity } = action.payload;
      const existingItem = state.items.find((item) => item.id === id);

      if (existingItem) {
        existingItem.quantity += quantity;
        existingItem.cartTotal = existingItem.price * existingItem.quantity;
      } else {
        const newItem = { ...action.payload, cartTotal: action.payload.price * quantity };
        state.items.push(newItem);
      }

      // Update localStorage
      localStorage.setItem("cartItems", JSON.stringify(state.items));
    },
    removeItem: (state, action: PayloadAction<number>) => {
      // Update the Redux state
      state.items = state.items.filter((item) => item.id !== action.payload);

      // Update localStorage
      localStorage.setItem("cartItems", JSON.stringify(state.items));
    },
    updateQuantity: (state, action: PayloadAction<{ id: number; quantity: number }>) => {
      // Find the item by ID and update its quantity and cartTotal
      const itemToUpdate = state.items.find((item) => item.id === action.payload.id);
      if (itemToUpdate) {
        itemToUpdate.quantity = action.payload.quantity;
        itemToUpdate.cartTotal = itemToUpdate.price * action.payload.quantity;
      }

      // Update localStorage
      localStorage.setItem("cartItems", JSON.stringify(state.items));
    },
  },
});

export const { addItem, removeItem, updateQuantity } = cartSlice.actions;

export default cartSlice.reducer;






